-- ============================================================================
-- CBox 同步服务 — 数据库初始化脚本
-- 用于首次创建数据库 / install.sh 交互安装
-- ============================================================================

CREATE DATABASE IF NOT EXISTS sync_server
  CHARACTER SET utf8mb4
  COLLATE utf8mb4_unicode_ci;

USE sync_server;

-- ============================================================================
-- 说明
-- ============================================================================
-- 表结构由 SQLAlchemy ORM 自动创建（main.py lifespan > init_db()）。
-- 本脚本仅 INSERT 预置数据。
--
-- install.sh 交互安装时:
--   Step 5 询问「是否使用默认管理员？」
--     [1] 是 → 写入 .env ADMIN_USERNAME=admin ADMIN_PASSWORD=admin123456789
--              main.py 启动时 ORM 自动建表后检测到已有同名用户，跳过创建
--     [2] 否 → 交互输入自定义用户名/密码 → 写入 .env
--              main.py 启动时 ORM 建表后自动创建自定义管理员
-- ============================================================================

-- ============================================================================
-- 预置默认管理员
--   用户名: admin
--   密码:   admin123456789  (bcrypt 哈希存储, 安装后可修改)
--   角色:   管理员 (is_admin = TRUE)
--   头像:   系统默认头像 (28,478 bytes JPEG)
-- ============================================================================

INSERT INTO users (uuid, username, nickname, email, password_hash, is_admin,
                   totp_enabled, created_at, updated_at,
                   avatar_url, avatar_data, avatar_mime, avatar_updated_at)
SELECT 'd0088677-e60b-4a75-968b-651111e3218a', 'admin', '管理员', 'admin@localhost',
       '$2b$12$6gzWIGJBGk4CFmDVXdI6/e47ia1u3ewQLGSu7qtjWRWSQ2mPh6.AC', TRUE, FALSE, '2026-07-01 23:57:49', '2026-07-01 23:57:49',
       '/static/default-avatar.jpg',
       UNHEX(''), 'image/jpeg', '2026-07-01 23:57:49'
WHERE NOT EXISTS (SELECT 1 FROM users WHERE username = 'admin');
